UPDATE t_product
SET product_name = #{productName}, brand_name = #{brandName}, category = #{category}
WHERE platform = #{platform} AND product_id = #{productId}

mapper.delete:
BEGIN
    DELETE FROM t_aspect_sentiment WHERE platform = #{platform} AND product_id = #{productId};
    DELETE FROM t_review WHERE platform = #{platform} AND product_id = #{productId};
    DELETE FROM t_product WHERE platform = #{platform} AND product_id = #{productId};
END;
